import Node from './Node';

import parentLog from './log';
const log = parentLog.createChild('Cache');


export type NodeCallback = (err, node?:Node)=>void;
export type LoadCallback = (id:string, callback:NodeCallback)=>void


/** Cache Class. Holds loaded nodes for a model that `begin()` has been
 * called on.
 *
 * @class Cache
 * @memberof jibo.kb
 * @intdocs
 */
class Cache {
    /** Retreive a node object from the cache.
     *
     * @method jibo.kb.Cache#fetch
     * @param {string} id ID of node to fetch.
     * @param {boolean} [quietly=false] Suppress warning message about node not found in cache.
     * @returns {jibo.kb.Node} Node object if found in cache or undefined if not.
     * @intdocs
     */
    public fetch(id:string, quietly=false):Node {
        let node = undefined;
        if (id in this) {
            node = this[id];
        } else {
            if (!quietly) {
                log.warn('fetch id', id, 'not in cache');
            }
        }
        return node;
    }


    /** Add a node object to the cache.
     *
     * @method jibo.kb.Cache#add
     * @param {jibo.kb.Node} node Node object to add.
     * @param {boolean} [quietly=false] Suppress warning message if node was already in cache (first in cache wins).
     * @intdocs
     */
    public add(node:Node, quietly=false) {
        if (node && node._id) {
            //log.debug('add', node._id);
            this._add(node._id, node, quietly);
        } else {
            log.error('add: can not add invalid object', node);
        }
    }


    /** Remove a node object from the cache.
     *
     * @method jibo.kb.Cache#remove
     * @param {string|jibo.kb.Node} idOrNode ID string or Node object to be removed.
     * @param {boolean} [quietly=false] Suppress warning message about node not found in cache.
     * @intdocs
     */
    public remove(idOrNode:string|Node, quietly=false) {
        let id:string = this._toId(idOrNode);
        if (id) {
            if (id in this) {
                delete this[id];
            } else {
                if (!quietly) {
                    log.warn('remove: id not in cache', id);
                }
            }
        } else {
            log.error('remove: invalid idOrNode', idOrNode);
        }
    }


    /** Check if node is present in cache.
     *
     * @method jibo.kb.Cache#isPresent
     * @param {string|jibo.kb.Node} idOrNode ID string or Node object to check cache for.
     * @returns {boolean} `true` if node is in cache.
     */
    public isPresent(idOrNode:string|Node):boolean {
        let id = this._toId(idOrNode);
        if (!id) {
            log.error('isPresent: invalid idOrNode', idOrNode);
        }
        return (id in this);
    }


    /** If a node is present in cache, return it (via callback),
     * otherwise use the given `load` function to load it and put the
     * loaded node into the cache before calling `callback`.
     *
     * @method jibo.kb.Cache#interceptLoad
     * @param {string} id ID of node to fetch or load.
     * @param {Function} callback Called with found or loaded node, (err, node).
     * @param {Function} load Function to call to load the node if not already in cache, (id, callback).
     * @intdocs
     */
    public interceptLoad(id:string, callback:NodeCallback, load:LoadCallback) {
        let node = this.fetch(id, true);
        if (node) {
            // make both branches async
            setImmediate( () => {
                callback(null, node);
            });
        } else {
            // is there a race condition here? can something else load
            // a node and stick it in the cache inbetween?  maybe we
            // need a task queue like nedb has? or maybe the nedb
            // queue helps us out here?
            load(id, (err, loadedNode) => {
                if (!err) {
                    if (loadedNode) {
                        this.add(loadedNode);
                    } else {
                        this._add(id, null);  // add to cache even if not found (record negative results too)
                    }
                }
                callback(err, loadedNode);
            });
        }
    }


    /** Add a value the cache.
     *
     * @method jibo.kb.Cache#_add
     * @param {string} id Id of value to add.
     * @param {any} value Value to be added to cache.
     * @param {boolean} [quietly=false] Suppress warning message if node was already in cache (first in cache wins).
     * @private
     * @intdocs
     */
    private _add(_id:string, value:any, quietly=false) {
        if (!(_id in this)) {  // careful! 'in' has lower precedence than '!'
            this[_id] = value;  // add to cache
        } else if (this[_id] === null) {
            // we allow overwriting nulls to allow creation of new nodes
            this[_id] = value;  // add to cache
        } else {
            if (Object.is(value, this[_id])) {
                if (!quietly) {
                    log.warn('add: there was already an entry in the cache for node id', _id);
                }
            } else {
                log.warn('add: existing entry for node id', _id, 'and new object does not match it!');
                // we should still just replace it in the cache
                this[_id] = value;  // add to cache
            }
        }
    }


    /** Convert an idOrNode parameter to an id if it's a node.
     *
     * @method jibo.kb.Cache#_toId
     * @param {string|Node} Id string, or node with an ._id property
     * @returns {string} Id
     * @private
     * @intdocs
     */
    private _toId(idOrNode:string|Node):string {
        if (typeof idOrNode === 'object') {
            idOrNode = (<Node>idOrNode)._id;
        }
        return <string>idOrNode;
    }
}


export default Cache;
