import Collection = require('nedb');

import Node from './Node';

import parentLog from './log';
const log = parentLog.createChild('Database');


export type CountCallback = (err, count?:number)=>void;
export type NodeCallback = (err, node?:Node)=>void;
export type NodesCallback = (err, nodes?:Node[])=>void;

/**
 * Database Class. Interface to Node Embedded Database (NeDB).
 *
 * @class Database
 * @memberof jibo.kb
 * @param {string} filename Full path filename to NeDB file.
 * @intdocs
 */
export default class Database {
    public filename:string;
    public nodes;//:Collection;

    constructor(filename:string) {
        this.filename = filename;
    }


    /** Attach to the NeDB filename given in constructor. File is
     * compacted upon opening, or created if it doesn't exist.
     *
     * @method jibo.kb.Database#init
     * @param {Function} callback Called when done compacting/creating/attaching.
     * @intdocs
     */
    public init(callback:CountCallback) {
        this.nodes = new Collection({ filename: this.filename });
        this.nodes.loadDatabase((err) => {
            log.iferr(err, 'Collection#loadDatabase for nodes', this.filename);
            if (!err) {
                this.nodes.count({}, (err, count) => {
                    // just informational
                    log.iferr(err, 'error counting nodes in', this.filename);
                    if (!err) {
                        log.info(count, 'KB node'+((count===1) ?'':'s')+' in', this.filename);
                    }
                    callback(err, count);
                });
            } else { callback(err); }
        });
    }


    /** Load node of given id. Returns null (via callback) if
     * not found.
     *
     * @method jibo.kb.Database#load
     * @param {string} id ID of node to load.
     * @param {Function} callback Called with (err, node). Node (and err) is null if not found.
     * @intdocs
     */
    public load(id:string, callback:NodeCallback) {
        this.nodes.findOne({ _id: id}, (err, node) => {
            log.iferr(err, 'Database#findOne of', id, 'on', this.filename);
            callback(err, <Node>node);
        });
    }


    /** Load nodes of the given array of ids. Returns null (via callback) for
     * each node that isn't found.
     *
     * @method jibo.kb.Database#loadList
     * @param {string} id ID of node to load.
     * @param {Function} callback Called with (err, nodes). Each node (and err) is null if not found.
     * @intdocs
     */
    public loadList(ids:string[], callback:NodesCallback) {
        this.nodes.find({_id: {$in: ids}}, (err, nodes) => {
            log.iferr(err, 'Database#find of _id $in ', ids, 'on', this.filename);
            callback(err, <Node[]>nodes);
        });
    }


    /** Load one node of a given type. Used to find the 'root' node.
     *
     * @method jibo.kb.Database#loadNodeOfType
     * @param {string} nodeType Node type to load.
     * @param {Function} callback Called with (err, node). Node (and err) is null if not found.
     * @intdocs
     */
    public loadNodeOfType(nodeType:string, callback:NodeCallback) {
        this.nodes.findOne({ type: nodeType}, (err, node) => {
            log.iferr(err, 'Database#findOne of type', nodeType, 'on', this.filename);
            callback(err, <Node>node);
        });
    }


    /** Load every node (in this kb slice) of a given type.
     *
     * @method jibo.kb.Database#loadNodesOfType
     * @param {string} nodeType Node type to load.
     * @param {Function} callback Called with (err, nodes) where nodes
     * is an array of the found nodes.
     * @intdocs
     */
    public loadNodesOfType(nodeType:string, callback:NodesCallback) {
        let q = {type: nodeType};
        this.nodes.find(q).exec( (err, nodes) => {
            log.iferr(err, 'Collection#find error');
            callback(err, <Node[]>nodes);
        });
    }


    /** Save a given node.
     *
     * @method jibo.kb.Database#save
     * @param {jibo.kb.Node} node The node to be saved.
     * @param {Function} callback Called with (err, node) when finished.
     * @intdocs
     */
    public save(node:Node, callback:NodeCallback) {
        if (!node._id) {
            throw new Error('node does not have an id');
        }
        this.nodes.update({ _id: node._id}, node, {upsert: true}, (err, numReplaced /*,upsert*/) => {
            log.iferr(err, 'Collection#update error', this.filename);
            if (err) {
                node._id = undefined;
            }
            if (callback) {
                callback(err, node);
            }
        });
    }


    /** Remove a node from this kb slice.
     *
     * @method jibo.kb.Database#remove
     * @param {string|jibo.kb.Node} idOrNode Id string or Node object to be removed.
     * @param {Function} callback Called with (err, numRemoved) when finished.
     * @intdocs
     */
    public remove(idOrNode:string|Node, callback:CountCallback) {
        let id:string = this._toId(idOrNode);
        this.nodes.remove({_id: id}, {}, (err, numRemoved) => {
            log.iferr(err, 'Database#remove of', id, 'on', this.filename);
            if (callback) {
                callback(err, numRemoved);
            }
        });
    }


    /** Convert an idOrNode parameter to an id if it's a node.
     *
     * @method jibo.kb.Database#_toId
     * @param {string|jibo.kb.Node} ID string, or node with an ._id property.
     * @returns {string} ID
     * @private
     * @intdocs
     */
    private _toId(idOrNode:string|Node):string {
        if (typeof idOrNode === 'object') {
            idOrNode = (<Node>idOrNode)._id;
        }
        return <string>idOrNode;
    }
}
