import fs = require('fs');
import fsExtra = require('fs-extra');

import KnowledgeDatabase from './KnowledgeDatabase';

import parentLog from './log';
const log = parentLog.createChild('DatabaseManager');


export type CreateCallback = (err, created?:boolean)=>void;
export type ExistsCallback = (err, exists?:boolean)=>void;
export type KnowledgeDatabaseCallback = (err, database?:KnowledgeDatabase)=>void;


/** Manager to keep track of created KnowledgeDatabase objects by name
 * to ensure they have a single instance. Only important for file
 * based KnowledgeDatabases, not really needed for the Web Client.
 *
 * Instantiated once as a singleton when imported by {@link jibo.kb.Model}.
 *
 * @class DatabaseManager
 * @memberof jibo.kb
 * @intdocs
 */
export class DatabaseManager {
    public static databases:{[kbName:string]:KnowledgeDatabase} = {};


    public static get(kbName:string, callback:KnowledgeDatabaseCallback) {
        let database = this.databases[kbName];
        if (database) {
            setImmediate( () => {
                callback(null, database);
            });
        } else {
            this.exists(kbName, (err, exists) => {
                if (err || !exists) {
                    callback(new Error('KB slice '+kbName+' does not exist, create it first'));
                } else {
                    database = new KnowledgeDatabase(kbName);
                    this.databases[kbName] = database;
                    database.init( (err) => {
                        log.iferr(err, 'KnowledgeDatabase.init');
                        if (!err) {
                            callback(null, database);
                        } else {
                            callback(err);
                        }
                    });
                }
            });
        }
    }


    // static version of DatabaseManager#exists()
    public static exists(kbName:string, callback:ExistsCallback) {
        const dbFilename = KnowledgeDatabase.getKbFilename(kbName);
        fs.access(dbFilename, (err) => {
            let exists = !err;
            callback(null, exists);
        });
    }


    // constructor() {
    //     //this.databases = {};
    // }


    public get databases():{[kbName:string]:KnowledgeDatabase} {
        return DatabaseManager.databases;
    }


    /** Create a KB slice if it doesn't exist.
     *
     * @method jibo.kb.DatabaseManager#create
     * @param {string} kbName KB slice name.
     * @param {Function} callback Called when done with (err,
     * created). `created` will be `true` if the KB slice needed to be
     * created, `false` if it already existsed.
     * @intdocs
     */
    public create(kbName:string, callback:CreateCallback) {
        if (this.databases[kbName]) {  // if we have it open it already exists
            setImmediate( () => {
                callback(null, false);
            });
        } else {
            const dbDirectory = KnowledgeDatabase.getKbDirectory(kbName);
            fsExtra.ensureDir(dbDirectory, (err) => {
                if (err) {
                    callback(err);
                } else {
                    const dbFilename = KnowledgeDatabase.getKbFilename(kbName);
                    fs.open(dbFilename, 'ax', (err, fd) => {
                        let created = false;
                        if (err) {
                            if (err && err.code === 'EEXIST') {
                                err = null;
                                created = false;
                            }
                        } else {
                            fs.close(fd);
                            created = true;
                        }
                        callback(err, created);
                    });
                }
            });
        }
    }


    /** Check if a KB slice was already created.
     *
     * @method jibo.kb.DatabaseManager#exists
     * @param {string} kbName KB slice name.
     * @param {Function} callback Called when done with (err, exists).
     * @intdocs
     */
    public exists(kbName:string, callback:ExistsCallback) {
        DatabaseManager.exists(kbName, callback);
    }


    /** Fetch or instantiate a new
     * [KnowledgeDatabase]{@link jibo.kb.KnowledgeDatabase}
     * based on the name. The KB slice must already exist.
     *
     * @method jibo.kb.DatabaseManager#get
     * @param {string} kbName KB slice name.
     * @param {Function} callback Called when done with (err, database).
     * @intdocs
     */
    public get(kbName:string, callback:KnowledgeDatabaseCallback) {
        DatabaseManager.get(kbName, callback);
    }


    /** Delete a KnowledgeDatabase from the in-memory cache.
     *
     * @method jibo.kb.DatabaseManager#release
     * @param {string} kbName Name of kb slice to release.
     * @intdocs
     */
    public release(kbName:string) {
        delete this.databases[kbName];
    }
}

export default DatabaseManager;
